package com.baize.flux.server.http;
import com.baize.flux.server.service.JobRestService; import com.fasterxml.jackson.databind.ObjectMapper; import javax.servlet.http.*; import java.io.*; import java.util.*;
/** 共用 JSON 输出和受控错误格式，绝不把堆栈发送给客户端。 */
public abstract class FluxServlet extends HttpServlet { protected final JobRestService service; protected final ObjectMapper json=new ObjectMapper(); protected FluxServlet(JobRestService s){service=s;} protected void write(HttpServletResponse r,int status,Object body)throws IOException{r.setStatus(status);r.setContentType("application/json;charset=UTF-8");json.writeValue(r.getOutputStream(),body);} protected String body(HttpServletRequest r)throws IOException{StringBuilder b=new StringBuilder();char[] c=new char[4096];Reader x=r.getReader();int n;while((n=x.read(c))>=0)b.append(c,0,n);return b.toString();} protected void error(HttpServletRequest req,HttpServletResponse resp,Exception e)throws IOException{int s=e instanceof IllegalArgumentException?400:e instanceof NoSuchElementException?404:e instanceof IllegalStateException?409:500;Map<String,String> b=new LinkedHashMap<String,String>();b.put("code","FLUX-REST-"+s);b.put("message",e.getMessage()==null?"Internal server error":e.getMessage());b.put("requestId",UUID.randomUUID().toString());write(resp,s,b);} }
